"use client";

import { useEffect, useMemo, useRef } from "react";
import { ReactFlowProvider } from "@xyflow/react";
import { Canvas } from "./parts/canvas";
import {
  FlowCanvasContextProvider,
  type FlowCanvasContextValue,
} from "./registries/canvas-context";
import { defaultPortTypes } from "./registries/port-type-registry";
import { mergeRenderers } from "./registries/renderer-registry";
import { mergeEdgeTypes } from "./registries/edge-type-registry";
import type { FlowCanvasProps, PortType } from "./types";

import "@xyflow/react/dist/style.css";

function mergePortTypes(consumer: PortType[] | undefined): PortType[] {
  const merged: PortType[] = [...defaultPortTypes];
  const seen = new Set<string>(merged.map((p) => p.id));
  for (const p of consumer ?? []) {
    if (seen.has(p.id) && process.env.NODE_ENV !== "production") {
      console.warn(
        `[flow-canvas-01] port type collision for "${p.id}" — last-wins`,
      );
    }
    const idx = merged.findIndex((m) => m.id === p.id);
    if (idx >= 0) merged[idx] = p;
    else merged.push(p);
    seen.add(p.id);
  }
  return merged;
}

export function FlowCanvas({
  renderers,
  portTypes,
  edgeTypes,
  readOnly = false,
  selectionMode = "multi",
  onNodeUpdate,
  onEditRequest,
  ...rest
}: FlowCanvasProps) {
  // v0.2.1 — ref-mirror consumer's onEditRequest so its identity changing
  // doesn't invalidate the canvas-context memo on every render. Matches the
  // existing defensive posture in use-canvas-data.ts (which ref-mirrors
  // onChange / onBeforeConnect / etc.). Plan §4.3.2 (F-V5 lock).
  const onEditRequestRef = useRef(onEditRequest);
  useEffect(() => {
    onEditRequestRef.current = onEditRequest;
  });

  // Stable wrapper — identity flips ONLY when consumer transitions between
  // wired and unwired states, not when they pass a fresh function identity
  // each render. Common consumer pattern: inline arrow on every render.
  const wiredOnEditRequest = onEditRequest !== undefined;
  const stableOnEditRequest = useMemo<
    FlowCanvasContextValue["onEditRequest"]
  >(
    () =>
      wiredOnEditRequest
        ? (nodeId, subPath) => onEditRequestRef.current?.(nodeId, subPath)
        : undefined,
    [wiredOnEditRequest],
  );

  const ctx = useMemo<FlowCanvasContextValue>(
    () => ({
      renderers: mergeRenderers(renderers),
      portTypes: mergePortTypes(portTypes),
      edgeTypes: mergeEdgeTypes(edgeTypes),
      readOnly,
      selectionMode,
      onNodeUpdate,
      onEditRequest: stableOnEditRequest,
    }),
    [
      renderers,
      portTypes,
      edgeTypes,
      readOnly,
      selectionMode,
      onNodeUpdate,
      stableOnEditRequest,
    ],
  );

  return (
    <ReactFlowProvider>
      <FlowCanvasContextProvider value={ctx}>
        <Canvas
          data={rest.data}
          defaultData={rest.defaultData}
          onChange={rest.onChange}
          onBeforeDrop={rest.onBeforeDrop}
          onBeforeConnect={rest.onBeforeConnect}
          onNodeCreate={rest.onNodeCreate}
          onNodeUpdate={onNodeUpdate}
          onNodeDelete={rest.onNodeDelete}
          onEdgeCreate={rest.onEdgeCreate}
          onEdgeDelete={rest.onEdgeDelete}
          onSubObjectExtract={rest.onSubObjectExtract}
          menuItems={rest.menuItems}
          panOnDrag={rest.panOnDrag}
          zoomOnScroll={rest.zoomOnScroll}
          selectionMode={selectionMode}
          readOnly={readOnly}
          onlyRenderVisibleElements={rest.onlyRenderVisibleElements}
          exportRef={rest.exportRef}
          backgroundConfig={rest.background}
          ariaLabel={rest["aria-label"]}
          className={rest.className}
        />
      </FlowCanvasContextProvider>
    </ReactFlowProvider>
  );
}

export { FlowCanvas } from "./flow-canvas-01";

export type {
  CanvasData,
  EdgeRecord,
  EdgeRenderContext,
  EdgeRenderer,
  FlowCanvasBackgroundConfig,
  FlowCanvasExportHandle,
  FlowCanvasProps,
  MenuItem,
  NodeData,
  NodeRecord,
  NodeRenderer,
  Port,
  PortDir,
  PortSide,
  PortType,
  PortsAtProps,
  RenderContext,
} from "./types";

export {
  customJsonRenderer,
  findRenderer,
  mergeRenderers,
  useRenderer,
} from "./registries/renderer-registry";
export {
  defaultPortTypes,
  findPortType,
  usePortType,
} from "./registries/port-type-registry";
export {
  defaultEdgeRenderer,
  findEdgeType,
  mergeEdgeTypes,
  useEdgeType,
} from "./registries/edge-type-registry";

export { PortsAt } from "./parts/ports-at";
export { PortHandle } from "./parts/port-handle";

export { findPortInTree, countEdgesAtPort } from "./lib/port-walker";
export type { FoundPort } from "./lib/port-walker";

export { emitSubObjectDrag } from "./lib/emit-sub-object-drag";

export { updateNodeData } from "./lib/update-node-data";

import type { ReactNode, Ref } from "react";

// ───── Port — embedded inside data at any tree depth ─────

export type PortDir = "in" | "out";
export type PortSide = "left" | "right" | "top" | "bottom";

export type Port = {
  id: string;
  side: PortSide;
  dir: PortDir;
  type: string;
  multi?: boolean;
  label?: string;
};

// ───── Node data — pure JSON, schema-discriminated, ports recursive ─────

export type NodeData = {
  __type: string;
  ports?: Port[];
  [key: string]: unknown;
};

export type NodeRecord = {
  id: string;
  position: { x: number; y: number };
  data: NodeData;
  width?: number;
  height?: number;
  selected?: boolean;
  locked?: boolean;
};

export type EdgeRecord = {
  id: string;
  source: `${string}:${string}`;
  target: `${string}:${string}`;
  type?: string;
  selected?: boolean;
};

export type CanvasData = {
  version: 1;
  nodes: NodeRecord[];
  edges: EdgeRecord[];
  viewport?: { x: number; y: number; zoom: number };
};

// ───── Registries ─────

export type RenderContext = {
  nodeId: string;
  isSelected: boolean;
  isDragging: boolean;
  isReadOnly: boolean;
  renderChild: (data: NodeData, opts?: { path?: string }) => ReactNode;

  /**
   * Fire from a renderer's click / keyboard-activate handler to request an
   * edit-dialog open for the current node. v0.2.1 addition.
   *
   * - Bound to the renderer's current `nodeId` — renderers call it with NO
   *   nodeId argument (the host already knows which node fired).
   * - Optional `subPath` argument lets renderers signal sub-targeting (e.g.
   *   a clicked subcard inside a rich-card viewer); the host forwards
   *   `subPath` to `FlowCanvasProps.onEditRequest` verbatim.
   * - `undefined` when the consumer hasn't wired `FlowCanvasProps.onEditRequest`.
   *
   * See the popup-edit renderer convention in the procomp guide §8.3 (v0.2.0
   * docs) + the `rich-card-in-flow` procomp for the canonical implementation.
   */
  onEditRequest?: (subPath?: string) => void;
};

export type NodeRenderer<TData extends NodeData = NodeData> = {
  type: string;
  label: string;
  defaultPorts?: (data: TData) => Port[];
  defaultSubPorts?: (data: TData) => Record<string, Port[]>;
  render: (data: TData, ctx: RenderContext) => ReactNode;
  extractablePaths?: (data: TData) => string[];
};

export type PortType = {
  id: string;
  label?: string;
  color: string;
  icon?: ReactNode;
};

export type EdgeRenderContext = {
  edgeId: string;
  source: { node: NodeRecord; port: Port };
  target: { node: NodeRecord; port: Port };
  isSelected: boolean;
};

export type EdgeRenderer = {
  type: string;
  label?: string;
  render: (edge: EdgeRecord, ctx: EdgeRenderContext) => ReactNode;
};

// ───── Right-click menu ─────

export type MenuItem = {
  id: string;
  label: string;
  icon?: ReactNode;
  onSelect: () => void;
  disabled?: boolean;
  separatorBefore?: boolean;
};

// ───── The canvas component ─────

export type FlowCanvasBackgroundConfig = {
  light?: { from: string; to: string; angle?: number };
  dark?: { from: string; to: string; angle?: number };
  overlay?: "none" | "dots" | "grid" | "cross";
  overlayOpacity?: number;
};

export type FlowCanvasExportHandle = {
  export: (opts: { withPorts: boolean }) => CanvasData;
};

export type FlowCanvasProps = {
  renderers?: NodeRenderer[];
  portTypes?: PortType[];
  edgeTypes?: EdgeRenderer[];

  data?: CanvasData;
  defaultData?: CanvasData;
  onChange?: (next: CanvasData) => void;

  onBeforeDrop?: (
    incoming: unknown,
    point: { x: number; y: number },
  ) => NodeData | null;
  onBeforeConnect?: (
    edge: EdgeRecord,
    ctx: { source: Port; target: Port },
  ) => boolean | EdgeRecord;

  onNodeCreate?: (node: NodeRecord) => void;
  onNodeUpdate?: (node: NodeRecord) => void;
  onNodeDelete?: (nodeId: string) => void;
  onEdgeCreate?: (edge: EdgeRecord) => void;
  onEdgeDelete?: (edgeId: string) => void;
  onSubObjectExtract?: (
    parentId: string,
    path: string,
    gesture: "copy" | "move",
  ) => void;

  menuItems?: {
    canvas?: MenuItem[];
    node?: (node: NodeRecord) => MenuItem[];
    edge?: (edge: EdgeRecord) => MenuItem[];
  };

  background?: FlowCanvasBackgroundConfig;

  readOnly?: boolean;
  panOnDrag?: boolean;
  zoomOnScroll?: boolean;
  selectionMode?: "single" | "multi";

  /**
   * When true (default v0.2.0+), xyflow culls nodes + edges outside the
   * viewport before rendering. Transforms perf at large N (5k+ heavy: ~12×
   * FPS lift on one machine, per 2026-05-14 baseline). Marginal effect
   * below ~200 nodes.
   *
   * Known caveats (don't block adoption):
   * - All nodes still render on initial mount; culling kicks in after the
   *   first viewport movement (xyflow issue #4378).
   * - Offscreen edges may stutter if their offscreen target node has an
   *   explicit height (xyflow issue #4329).
   *
   * Pass `={false}` to opt out (e.g. if you rely on offscreen-node DOM for
   * layout measurement — rare).
   */
  onlyRenderVisibleElements?: boolean;

  /**
   * Fired when a renderer requests an edit-dialog open (typically click).
   * v0.2.1 addition.
   *
   * - `nodeId` is the node firing the request.
   * - `subPath` is an opaque renderer-defined string (e.g. a rich-card subcard's
   *   `__rcid`) for sub-targeting; pass it through to your editor (e.g. via
   *   `RichCardHandle.focusCard(subPath)` for the rich-card-in-flow case).
   * - Leave `undefined` if you don't want edit affordances; renderers that
   *   honor the convention will silently no-op (their `ctx.onEditRequest`
   *   will be `undefined`).
   *
   * See the popup-edit renderer convention in the procomp guide §8.3 + the
   * `rich-card-in-flow` procomp for the canonical consumer pattern.
   */
  onEditRequest?: (nodeId: string, subPath?: string) => void;

  exportRef?: Ref<FlowCanvasExportHandle>;

  "aria-label"?: string;

  className?: string;
};

// ───── Layout helper props ─────

export type PortsAtProps = {
  ports: Port[] | undefined;
  position: PortSide;
  spacing?: number;
};

"use client";

import {
  useCallback,
  useEffect,
  useMemo,
  useRef,
  useState,
} from "react";
import {
  addEdge as xyAddEdge,
  applyEdgeChanges,
  applyNodeChanges,
  type Connection,
  type Edge as XyEdge,
  type EdgeChange,
  type Node as XyNode,
  type NodeChange,
} from "@xyflow/react";
import { findPortInTree } from "../lib/port-walker";
import { removeAtPath } from "../lib/sub-object-paths";
import type {
  CanvasData,
  EdgeRecord,
  FlowCanvasProps,
  NodeData,
  NodeRecord,
  Port,
} from "../types";

const EMPTY: CanvasData = { version: 1, nodes: [], edges: [] };

function makeEdgeId(): string {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return `e-${crypto.randomUUID()}`;
  }
  return `e-${Math.random().toString(36).slice(2, 10)}`;
}

function makeNodeId(): string {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }
  return `n-${Math.random().toString(36).slice(2, 10)}`;
}

// xyflow's Node type carries `type`, `data`, `position`, etc. Our adapter
// always sets type to "ilinxa-node"; data carries our NodeData shape with
// a stable `id` mirror so the canvas can find it without our custom store.
type XyNodeData = NodeRecord["data"];

function toXyNode(n: NodeRecord): XyNode<XyNodeData> {
  return {
    id: n.id,
    type: "ilinxa-node",
    position: n.position,
    data: n.data,
    width: n.width,
    height: n.height,
    selected: n.selected,
    draggable: n.locked ? false : undefined,
  };
}

function toXyEdge(e: EdgeRecord): XyEdge {
  // xyflow expects sourceHandle / targetHandle as separate fields. Our
  // EdgeRecord encodes them inline as 'nodeId:portId'.
  const [source, sourceHandle] = e.source.split(":") as [string, string];
  const [target, targetHandle] = e.target.split(":") as [string, string];
  return {
    id: e.id,
    source,
    sourceHandle,
    target,
    targetHandle,
    type: e.type ?? "ilinxa-edge",
    selected: e.selected,
  };
}

function fromXyNode(n: XyNode<XyNodeData>): NodeRecord {
  return {
    id: n.id,
    position: n.position,
    data: n.data as XyNodeData,
    width: typeof n.width === "number" ? n.width : undefined,
    height: typeof n.height === "number" ? n.height : undefined,
    selected: n.selected,
    locked: n.draggable === false ? true : undefined,
  };
}

function fromXyEdge(e: XyEdge): EdgeRecord {
  const sourceHandle = e.sourceHandle ?? "";
  const targetHandle = e.targetHandle ?? "";
  return {
    id: e.id,
    source: `${e.source}:${sourceHandle}`,
    target: `${e.target}:${targetHandle}`,
    type: e.type === "ilinxa-edge" ? undefined : e.type,
    selected: e.selected,
  };
}

export type UseCanvasDataResult = {
  // xyflow-shaped state for direct binding to <ReactFlow>
  xyNodes: XyNode<XyNodeData>[];
  xyEdges: XyEdge[];
  onNodesChange: (changes: NodeChange<XyNode<XyNodeData>>[]) => void;
  onEdgesChange: (changes: EdgeChange<XyEdge>[]) => void;
  onConnect: (connection: Connection) => void;
  // Drag lifecycle — bind to <ReactFlow>'s onNodeDragStart/onNodeDragStop
  // props. During a drag the per-tick onChange is suppressed (position-only
  // changes are batched); onNodeDragStop flushes a single final fire with
  // the committed state. Internal only — not re-exported from index.ts.
  onNodeDragStart: () => void;
  onNodeDragStop: () => void;
  // Snapshot in our CanvasData shape (used by exportRef + viewport setters)
  snapshot: () => CanvasData;
  // Imperative helpers used by drop pipeline / sub-object extract / menus
  appendNode: (node: NodeRecord) => void;
  updateNodeData: (nodeId: string, mutate: (data: NodeData) => NodeData) => void;
  duplicateNode: (nodeId: string) => void;
  deleteNode: (nodeId: string) => void;
  deleteEdge: (edgeId: string) => void;
  setEdges: (edges: EdgeRecord[]) => void;
  setNodes: (nodes: NodeRecord[]) => void;
  replace: (data: CanvasData) => void;
  // Sub-object extraction (atomic: append + optionally remove from parent)
  extractSubObject: (input: {
    parentId: string;
    path: string;
    gesture: "copy" | "move";
    newNode: NodeRecord;
  }) => void;
  // Ref-based resolvers — used by callers (e.g. <CanvasContextMenu>) that
  // need to look up nodes/edges by id without re-rendering on every state
  // change. The returned functions are stable across renders; the lookup
  // closes over a ref so it always sees the latest state.
  getNodeById: (id: string) => NodeRecord | undefined;
  getEdgeById: (id: string) => EdgeRecord | undefined;
};

export function useCanvasData({
  data,
  defaultData,
  onChange,
  onBeforeConnect,
  onNodeCreate,
  onNodeUpdate,
  onNodeDelete,
  onEdgeCreate,
  onEdgeDelete,
  onSubObjectExtract,
}: {
  data?: CanvasData;
  defaultData?: CanvasData;
  onChange?: (next: CanvasData) => void;
  onBeforeConnect?: FlowCanvasProps["onBeforeConnect"];
  onNodeCreate?: FlowCanvasProps["onNodeCreate"];
  onNodeUpdate?: FlowCanvasProps["onNodeUpdate"];
  onNodeDelete?: FlowCanvasProps["onNodeDelete"];
  onEdgeCreate?: FlowCanvasProps["onEdgeCreate"];
  onEdgeDelete?: FlowCanvasProps["onEdgeDelete"];
  onSubObjectExtract?: FlowCanvasProps["onSubObjectExtract"];
}): UseCanvasDataResult {
  const isControlled = data !== undefined;
  const initial = data ?? defaultData ?? EMPTY;

  const [internalNodes, setInternalNodes] = useState<XyNode<XyNodeData>[]>(() =>
    initial.nodes.map(toXyNode),
  );
  const [internalEdges, setInternalEdges] = useState<XyEdge[]>(() =>
    initial.edges.map(toXyEdge),
  );
  const [viewport, setViewport] = useState(initial.viewport);

  // Refs mirror the latest state so we can keep event handlers stable
  // (empty-dep useCallback). This is the canonical xyflow perf pattern —
  // see xyflow-react-pro skill "Performance" + "useCallback every event
  // handler". At 200 nodes, dep-changing handlers cascade into a full
  // ReactFlow reconciliation on every drag tick.
  const nodesRef = useRef(internalNodes);
  const edgesRef = useRef(internalEdges);
  const viewportRef = useRef(viewport);
  // Drag-lifecycle ref — flipped true between xyflow's onNodeDragStart and
  // onNodeDragStop. While true, the position-only onNodesChange path skips
  // the consumer onChange (per-tick suppression); onNodeDragStop flushes
  // one final fire with the committed state. v0.2.0 Tier 1 perf change.
  const isDraggingRef = useRef(false);
  useEffect(() => {
    nodesRef.current = internalNodes;
  }, [internalNodes]);
  useEffect(() => {
    edgesRef.current = internalEdges;
  }, [internalEdges]);
  useEffect(() => {
    viewportRef.current = viewport;
  }, [viewport]);

  // Also mirror callback props in refs so changing the consumer's callback
  // identity doesn't churn our internal handlers.
  const onChangeRef = useRef(onChange);
  const onBeforeConnectRef = useRef(onBeforeConnect);
  const onNodeCreateRef = useRef(onNodeCreate);
  const onNodeUpdateRef = useRef(onNodeUpdate);
  const onNodeDeleteRef = useRef(onNodeDelete);
  const onEdgeCreateRef = useRef(onEdgeCreate);
  const onEdgeDeleteRef = useRef(onEdgeDelete);
  const onSubObjectExtractRef = useRef(onSubObjectExtract);
  useEffect(() => {
    onChangeRef.current = onChange;
    onBeforeConnectRef.current = onBeforeConnect;
    onNodeCreateRef.current = onNodeCreate;
    onNodeUpdateRef.current = onNodeUpdate;
    onNodeDeleteRef.current = onNodeDelete;
    onEdgeCreateRef.current = onEdgeCreate;
    onEdgeDeleteRef.current = onEdgeDelete;
    onSubObjectExtractRef.current = onSubObjectExtract;
  });

  // Reflect controlled-mode changes — `data` prop wholesale replacement
  const lastControlledData = useRef<CanvasData | undefined>(data);
  useEffect(() => {
    if (!isControlled) return;
    if (data === lastControlledData.current) return;
    lastControlledData.current = data;
    setInternalNodes((data ?? EMPTY).nodes.map(toXyNode));
    setInternalEdges((data ?? EMPTY).edges.map(toXyEdge));
    setViewport(data?.viewport);
  }, [isControlled, data]);

  // v0.2.2 lock: notify the consumer in a microtask AFTER React commits the
  // current state update. Why deferred:
  //
  // - `fireOnChange` is called from 13 sites in this file, MOST of which sit
  //   inside `setInternalNodes/Edges/Viewport((prev) => { ... })` reducers
  //   (the "reducer-side-effect" pattern acknowledged in v0.2.0 plan F-V4 as
  //   a v0.3 cleanup candidate). When xyflow emits initial `dimensions`
  //   changes during its own render-phase measurement, the reducer-side-
  //   effect fires the consumer's `onChange` synchronously → consumer's
  //   `setCanvas` → React 19 "setState during render" warning on the
  //   consumer component. Surfaced 2026-05-16 by rich-card-in-flow@v0.1.0's
  //   demo (first controlled-mode consumer in the library).
  //
  // - Wrapping the body in `queueMicrotask` gives ONE invariant: consumer
  //   `onChange` always fires post-commit. Every code path in this file
  //   becomes render-phase-safe — no need to refactor each reducer-side-
  //   effect site individually. Promotes the v0.3-deferred cleanup forward
  //   because the bug surfaced; "consistency over a one-off divergence" per
  //   F-V4 still holds (all 13 sites get the SAME deferred behavior, not a
  //   mixed bag of one-microtask-deferred + twelve-still-synchronous).
  //
  // - Capture semantics: `nodes` / `edges` / `vp` are captured in closure.
  //   Post-`applyNodeChanges`/`applyEdgeChanges`/`xyAddEdge` arrays are
  //   immutable; the `.map(fromXyNode)` runs at microtask time but reads
  //   the captured references — consumer always sees the state that the
  //   call site intended to notify about, not whatever state happens to be
  //   current at microtask-execution time.
  //
  // - Latency: one microtask. Imperceptible. React batches the consumer's
  //   resulting setState into the next paint either way.
  const fireOnChange = useCallback(
    (
      nodes: XyNode<XyNodeData>[],
      edges: XyEdge[],
      vp: CanvasData["viewport"],
    ) => {
      queueMicrotask(() => {
        const cb = onChangeRef.current;
        if (!cb) return;
        cb({
          version: 1,
          nodes: nodes.map(fromXyNode),
          edges: edges.map(fromXyEdge),
          viewport: vp,
        });
      });
    },
    [],
  );

  const onNodesChange = useCallback(
    (changes: NodeChange<XyNode<XyNodeData>>[]) => {
      setInternalNodes((prev) => {
        const next = applyNodeChanges(changes, prev);
        // Skip the per-tick consumer callback during continuous drag IF all
        // changes in this batch are position changes. onNodeDragStop flushes
        // a single final fire when the drag ends. Mixed batches (e.g.
        // position + dimensions) still fire immediately so a consumer's
        // measurement-driven layout effect can't be silently delayed.
        const isAllPositionChanges = changes.every((c) => c.type === "position");
        if (isDraggingRef.current && isAllPositionChanges) {
          return next;
        }
        fireOnChange(next, edgesRef.current, viewportRef.current);
        return next;
      });
    },
    [fireOnChange],
  );

  // Drag-lifecycle callbacks — wired to <ReactFlow>'s onNodeDragStart /
  // onNodeDragStop props in canvas.tsx. The pair plus the position-only
  // short-circuit above implement description §4.1 Change #2 + #3 (batch
  // per-tick consumer fires during drag; skip the full re-map at end-of-drag
  // when only positions changed).
  const onNodeDragStart = useCallback(() => {
    isDraggingRef.current = true;
  }, []);

  const onNodeDragStop = useCallback(() => {
    isDraggingRef.current = false;
    // Flush a final onChange with the committed state. The setInternalNodes
    // reducer reads the latest committed value synchronously and returns it
    // unchanged (React bails out on identity-equal state, no re-render).
    // The reducer-side-effect pattern (here + 12 other sites in this file)
    // is now safe post-v0.2.2: `fireOnChange` is microtask-deferred in its
    // definition above, so it never runs synchronously during a reducer.
    setInternalNodes((latestNodes) => {
      fireOnChange(latestNodes, edgesRef.current, viewportRef.current);
      return latestNodes;
    });
  }, [fireOnChange]);

  const onEdgesChange = useCallback(
    (changes: EdgeChange<XyEdge>[]) => {
      setInternalEdges((prev) => {
        const next = applyEdgeChanges(changes, prev);
        fireOnChange(nodesRef.current, next, viewportRef.current);
        return next;
      });
    },
    [fireOnChange],
  );

  // onConnect — adds an edge after typed validation (in canvas.tsx) AND
  // the consumer's onBeforeConnect hook (here). Pipeline:
  //   xyflow drag-release
  //     → isValidConnection (typed: same-type + dir + multi)  [canvas.tsx]
  //     → onConnect          (this fn)
  //         → onBeforeConnect (consumer; can reject or rewrite the edge)
  //         → addEdge to state, fireOnChange, fire onEdgeCreate
  const onConnect = useCallback(
    (connection: Connection) => {
      let candidate: EdgeRecord = {
        id: makeEdgeId(),
        source: `${connection.source}:${connection.sourceHandle ?? ""}`,
        target: `${connection.target}:${connection.targetHandle ?? ""}`,
      };

      const before = onBeforeConnectRef.current;
      if (before) {
        const nodes = nodesRef.current;
        const srcNode = nodes.find((n) => n.id === connection.source);
        const tgtNode = nodes.find((n) => n.id === connection.target);
        const srcPort: Port | undefined =
          srcNode && connection.sourceHandle
            ? findPortInTree(srcNode.data as NodeData, connection.sourceHandle)?.port
            : undefined;
        const tgtPort: Port | undefined =
          tgtNode && connection.targetHandle
            ? findPortInTree(tgtNode.data as NodeData, connection.targetHandle)?.port
            : undefined;
        if (!srcPort || !tgtPort) return;

        const result = before(candidate, { source: srcPort, target: tgtPort });
        if (result === false) return;
        if (typeof result === "object" && result !== null) candidate = result;
      }

      setInternalEdges((prev) => {
        const next = xyAddEdge(
          {
            ...connection,
            id: candidate.id,
            type: "ilinxa-edge",
          },
          prev,
        );
        fireOnChange(nodesRef.current, next, viewportRef.current);
        return next;
      });
      onEdgeCreateRef.current?.(candidate);
    },
    [fireOnChange],
  );

  const snapshot = useCallback<() => CanvasData>(
    () => ({
      version: 1,
      nodes: nodesRef.current.map(fromXyNode),
      edges: edgesRef.current.map(fromXyEdge),
      viewport: viewportRef.current,
    }),
    [],
  );

  const appendNode = useCallback(
    (node: NodeRecord) => {
      setInternalNodes((prev) => {
        const next = [...prev, toXyNode(node)];
        fireOnChange(next, edgesRef.current, viewportRef.current);
        return next;
      });
      onNodeCreateRef.current?.(node);
    },
    [fireOnChange],
  );

  const updateNodeData = useCallback(
    (nodeId: string, mutate: (data: NodeData) => NodeData) => {
      let updatedRecord: NodeRecord | undefined;
      setInternalNodes((prev) => {
        const next = prev.map((n) => {
          if (n.id !== nodeId) return n;
          const updated = mutate(n.data as NodeData);
          updatedRecord = fromXyNode({ ...n, data: updated });
          return { ...n, data: updated };
        });
        fireOnChange(next, edgesRef.current, viewportRef.current);
        return next;
      });
      if (updatedRecord) onNodeUpdateRef.current?.(updatedRecord);
    },
    [fireOnChange],
  );

  const duplicateNode = useCallback(
    (nodeId: string) => {
      const target = nodesRef.current.find((n) => n.id === nodeId);
      if (!target) return;
      const clone: NodeRecord = {
        id: makeNodeId(),
        position: { x: target.position.x + 24, y: target.position.y + 24 },
        data: JSON.parse(JSON.stringify(target.data)),
      };
      appendNode(clone);
    },
    [appendNode],
  );

  const deleteNode = useCallback(
    (nodeId: string) => {
      // Cascade incident edges per Q15.
      setInternalEdges((prev) =>
        prev.filter((e) => e.source !== nodeId && e.target !== nodeId),
      );
      setInternalNodes((prev) => {
        const next = prev.filter((n) => n.id !== nodeId);
        fireOnChange(next, edgesRef.current, viewportRef.current);
        return next;
      });
      onNodeDeleteRef.current?.(nodeId);
    },
    [fireOnChange],
  );

  const deleteEdge = useCallback(
    (edgeId: string) => {
      setInternalEdges((prev) => {
        const next = prev.filter((e) => e.id !== edgeId);
        fireOnChange(nodesRef.current, next, viewportRef.current);
        return next;
      });
      onEdgeDeleteRef.current?.(edgeId);
    },
    [fireOnChange],
  );

  const setNodes = useCallback(
    (nodes: NodeRecord[]) => {
      const next = nodes.map(toXyNode);
      setInternalNodes(next);
      fireOnChange(next, edgesRef.current, viewportRef.current);
    },
    [fireOnChange],
  );

  const setEdges = useCallback(
    (edges: EdgeRecord[]) => {
      const next = edges.map(toXyEdge);
      setInternalEdges(next);
      fireOnChange(nodesRef.current, next, viewportRef.current);
    },
    [fireOnChange],
  );

  const replace = useCallback(
    (next: CanvasData) => {
      const xn = next.nodes.map(toXyNode);
      const xe = next.edges.map(toXyEdge);
      setInternalNodes(xn);
      setInternalEdges(xe);
      setViewport(next.viewport);
      fireOnChange(xn, xe, next.viewport);
    },
    [fireOnChange],
  );

  // Atomic sub-object extraction: append the new node AND (if 'move') remove
  // the sub-object from the parent's data tree in a single state update.
  // Plan §3.8 + Q23 — gesture defaults to 'copy' (parent retains).
  const extractSubObject = useCallback(
    ({
      parentId,
      path,
      gesture,
      newNode,
    }: {
      parentId: string;
      path: string;
      gesture: "copy" | "move";
      newNode: NodeRecord;
    }) => {
      let updatedParentRecord: NodeRecord | undefined;
      setInternalNodes((prev) => {
        const withChild = [...prev, toXyNode(newNode)];
        if (gesture === "copy") {
          fireOnChange(withChild, edgesRef.current, viewportRef.current);
          return withChild;
        }
        // Move — remove the sub-object from parent.data at `path`.
        const next = withChild.map((n) => {
          if (n.id !== parentId) return n;
          const nextData = removeAtPath(n.data as NodeData, path);
          updatedParentRecord = fromXyNode({ ...n, data: nextData });
          return { ...n, data: nextData };
        });
        fireOnChange(next, edgesRef.current, viewportRef.current);
        return next;
      });
      onNodeCreateRef.current?.(newNode);
      if (updatedParentRecord) onNodeUpdateRef.current?.(updatedParentRecord);
      onSubObjectExtractRef.current?.(parentId, path, gesture);
    },
    [fireOnChange],
  );

  const getNodeById = useCallback((id: string): NodeRecord | undefined => {
    const n = nodesRef.current.find((x) => x.id === id);
    return n ? fromXyNode(n) : undefined;
  }, []);

  const getEdgeById = useCallback((id: string): EdgeRecord | undefined => {
    const e = edgesRef.current.find((x) => x.id === id);
    return e ? fromXyEdge(e) : undefined;
  }, []);

  return useMemo(
    () => ({
      xyNodes: internalNodes,
      xyEdges: internalEdges,
      onNodesChange,
      onEdgesChange,
      onConnect,
      onNodeDragStart,
      onNodeDragStop,
      snapshot,
      appendNode,
      updateNodeData,
      duplicateNode,
      deleteNode,
      deleteEdge,
      setEdges,
      setNodes,
      replace,
      extractSubObject,
      getNodeById,
      getEdgeById,
    }),
    [
      internalNodes,
      internalEdges,
      onNodesChange,
      onEdgesChange,
      onConnect,
      onNodeDragStart,
      onNodeDragStop,
      snapshot,
      appendNode,
      updateNodeData,
      duplicateNode,
      deleteNode,
      deleteEdge,
      setEdges,
      setNodes,
      replace,
      extractSubObject,
      getNodeById,
      getEdgeById,
    ],
  );
}

"use client";

import { useCallback, type DragEvent, type ClipboardEvent } from "react";
import { useReactFlow } from "@xyflow/react";
import { coerceToNodeData } from "../lib/coerce-to-node-data";
import { inflateDefaultPorts } from "../lib/inflate-default-ports";
import { parseJsonSafe } from "../lib/parse-json";
import { findRenderer } from "../registries/renderer-registry";
import type {
  FlowCanvasProps,
  NodeData,
  NodeRecord,
  NodeRenderer,
} from "../types";

const NODE_DROP_MIME = "application/json";
// MIME used by xyflow's own sidebar pattern. We accept this too so consumers
// who already use that convention keep working.
const REACTFLOW_DROP_MIME = "application/reactflow";
// Custom MIME for in-canvas sub-object drag-extract (M5). Carries
// `parentId|path` so the drop handler can route through the extraction
// pipeline instead of treating it as an external JSON drop.
const SUBOBJECT_DROP_MIME = "application/x-ilinxa-subobject";

type DropContext = {
  renderers: NodeRenderer[];
  appendNode: (node: NodeRecord) => void;
  extractSubObject: (input: {
    parentId: string;
    path: string;
    gesture: "copy" | "move";
    newNode: NodeRecord;
  }) => void;
  onBeforeDrop?: FlowCanvasProps["onBeforeDrop"];
  onNodeCreate?: FlowCanvasProps["onNodeCreate"];
};

// Build the drag-over / drop / paste handlers. The caller spreads these onto
// the canvas wrapper element.
//
// `useReactFlow()` requires <ReactFlowProvider> in an ancestor — our root
// already provides it.
export function useDropPipeline({
  renderers,
  appendNode,
  extractSubObject,
  onBeforeDrop,
  onNodeCreate,
}: DropContext) {
  const { screenToFlowPosition } = useReactFlow();

  const buildNode = useCallback(
    (rawData: NodeData, point: { x: number; y: number }): NodeRecord | null => {
      let data: NodeData | null = rawData;
      if (onBeforeDrop) {
        const result = onBeforeDrop(rawData, point);
        if (result === null) return null;
        if (result) data = result;
      }
      if (!data) return null;
      const renderer = findRenderer(renderers, data.__type);
      const inflated = inflateDefaultPorts(data, renderer);
      return { id: makeNodeId(), position: point, data: inflated };
    },
    [renderers, onBeforeDrop],
  );

  const dispatch = useCallback(
    (rawData: NodeData, point: { x: number; y: number }) => {
      const node = buildNode(rawData, point);
      if (!node) return;
      // appendNode fires onNodeCreate internally now, but the prop hook also
      // runs here for parity with paste-without-renderer paths.
      appendNode(node);
      onNodeCreate?.(node);
    },
    [buildNode, appendNode, onNodeCreate],
  );

  const dispatchExtraction = useCallback(
    (
      rawData: NodeData,
      point: { x: number; y: number },
      parentId: string,
      path: string,
      gesture: "copy" | "move",
    ) => {
      const node = buildNode(rawData, point);
      if (!node) return;
      extractSubObject({ parentId, path, gesture, newNode: node });
    },
    [buildNode, extractSubObject],
  );

  const onDragOver = useCallback((e: DragEvent) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = "move";
  }, []);

  const onDrop = useCallback(
    (e: DragEvent) => {
      e.preventDefault();
      const dt = e.dataTransfer;

      // Sub-object extraction branch — own-canvas drag tagged by emitSubObjectDrag.
      const subPayload = dt.getData(SUBOBJECT_DROP_MIME);
      const jsonPayload = dt.getData(NODE_DROP_MIME);
      if (subPayload && jsonPayload) {
        const parsed = parseJsonSafe(jsonPayload);
        const data = coerceToNodeData(parsed);
        if (!data) return;
        const meta = parseJsonSafe(subPayload) as
          | { parentId?: string; path?: string }
          | undefined;
        if (!meta?.parentId || !meta.path) return;
        const point = screenToFlowPosition({ x: e.clientX, y: e.clientY });
        // Alt held → move; otherwise copy. Documented as the gesture.
        const gesture = e.altKey ? "move" : "copy";
        dispatchExtraction(data, point, meta.parentId, meta.path, gesture);
        return;
      }

      // Order of preference: explicit JSON, xyflow's reactflow MIME, plain text.
      const payload =
        jsonPayload ||
        dt.getData(REACTFLOW_DROP_MIME) ||
        dt.getData("text/plain");

      // No text payload — try files (first one only).
      if (!payload && dt.files.length > 0) {
        const file = dt.files[0];
        if (!file.type.includes("json") && !file.name.endsWith(".json")) return;
        // Read async; abort if it fails.
        file
          .text()
          .then((text) => {
            const parsed = parseJsonSafe(text);
            const data = coerceToNodeData(parsed);
            if (!data) return;
            const point = screenToFlowPosition({ x: e.clientX, y: e.clientY });
            dispatch(data, point);
          })
          .catch(() => undefined);
        return;
      }

      if (!payload) return;
      const parsed = parseJsonSafe(payload);
      const data = coerceToNodeData(parsed);
      if (!data) return;
      const point = screenToFlowPosition({ x: e.clientX, y: e.clientY });
      dispatch(data, point);
    },
    [screenToFlowPosition, dispatch, dispatchExtraction],
  );

  const onPaste = useCallback(
    (e: ClipboardEvent) => {
      // Don't steal paste from focused inputs/textareas/contenteditables.
      const target = e.target as HTMLElement | null;
      if (target && isEditableTarget(target)) return;

      const text = e.clipboardData.getData("text/plain");
      if (!text) return;
      const parsed = parseJsonSafe(text);
      const data = coerceToNodeData(parsed);
      if (!data) return;

      // Paste lands at the viewport center (no mouse coordinates available).
      // Compute via the canvas root's bounding box.
      const root =
        target && target.closest<HTMLDivElement>("[data-flow-canvas-root]");
      const rect = root?.getBoundingClientRect();
      const sx = rect ? rect.left + rect.width / 2 : window.innerWidth / 2;
      const sy = rect ? rect.top + rect.height / 2 : window.innerHeight / 2;
      const point = screenToFlowPosition({ x: sx, y: sy });

      e.preventDefault();
      dispatch(data, point);
    },
    [screenToFlowPosition, dispatch],
  );

  return { onDragOver, onDrop, onPaste };
}

function isEditableTarget(el: HTMLElement): boolean {
  if (el.isContentEditable) return true;
  const tag = el.tagName;
  return tag === "INPUT" || tag === "TEXTAREA" || tag === "SELECT";
}

function makeNodeId(): string {
  if (typeof crypto !== "undefined" && typeof crypto.randomUUID === "function") {
    return crypto.randomUUID();
  }
  return `n-${Math.random().toString(36).slice(2, 10)}`;
}

"use client";

import { useImperativeHandle, type Ref } from "react";
import type {
  CanvasData,
  EdgeRecord,
  FlowCanvasExportHandle,
  NodeData,
  NodeRecord,
} from "../types";

function stripPortsFromNodeData(data: NodeData): NodeData {
  const { ports: _ports, ...rest } = data;
  void _ports;
  const out: NodeData = { __type: data.__type };
  for (const [key, value] of Object.entries(rest)) {
    if (key === "__type") continue;
    out[key] = stripPortsFromValue(value);
  }
  return out;
}

function stripPortsFromValue(value: unknown): unknown {
  if (Array.isArray(value)) {
    return value.map((v) => stripPortsFromValue(v));
  }
  if (value && typeof value === "object") {
    const obj = value as Record<string, unknown>;
    if (typeof obj.__type === "string") {
      return stripPortsFromNodeData(obj as NodeData);
    }
    const cleaned: Record<string, unknown> = {};
    for (const [k, v] of Object.entries(obj)) {
      if (k === "ports") continue;
      cleaned[k] = stripPortsFromValue(v);
    }
    return cleaned;
  }
  return value;
}

function stripSelected<T extends { selected?: boolean }>(
  record: T,
): Omit<T, "selected"> {
  const { selected: _selected, ...rest } = record;
  void _selected;
  return rest;
}

export function useExportHandle(
  ref: Ref<FlowCanvasExportHandle> | undefined,
  getSnapshot: () => CanvasData,
) {
  useImperativeHandle(
    ref,
    () => ({
      export: ({ withPorts }) => {
        const snap = getSnapshot();
        if (withPorts) {
          return {
            ...snap,
            nodes: snap.nodes.map((n) => stripSelected(n) as NodeRecord),
            edges: snap.edges.map((e) => stripSelected(e) as EdgeRecord),
          };
        }
        return {
          ...snap,
          nodes: snap.nodes.map((n) => ({
            ...stripSelected(n),
            data: stripPortsFromNodeData(n.data),
          })) as NodeRecord[],
          edges: [],
        };
      },
    }),
    [getSnapshot],
  );
}

import type { NodeData } from "../types";

// Coerce arbitrary parsed JSON into a `NodeData` shape. Rules:
//   - `null` / non-objects / arrays → undefined (caller aborts)
//   - object with string `__type` → returned as-is (already NodeData)
//   - object without `__type`     → wrapped as `{ __type: 'custom-json', ...obj }`
//
// This is the canonical single-place where unknown payloads get the fallback
// discriminator. M5 sub-object extraction also funnels through here when an
// extracted sub-object lacks `__type` (description risk §10).

export function coerceToNodeData(input: unknown): NodeData | undefined {
  if (!input || typeof input !== "object") return undefined;
  if (Array.isArray(input)) return undefined;

  const obj = input as Record<string, unknown>;
  if (typeof obj.__type === "string" && obj.__type.length > 0) {
    return obj as NodeData;
  }
  return { __type: "custom-json", ...obj };
}

import type { DragEvent } from "react";

// Renderers call this from a sub-object's `onDragStart` to mark the drag as
// a sub-object extraction. The drop handler (canvas root) reads the special
// MIME and routes the drop through the extraction pipeline (copy by default,
// Alt-drag for move).
//
// Pattern (in a renderer):
//
//   <div
//     data-draggable-subobject={`media[${i}]`}
//     draggable
//     onDragStart={(e) => emitSubObjectDrag(
//       e, data.media[i], `media[${i}]`, ctx.nodeId
//     )}
//   >
//     <MediaItem {...data.media[i]} />
//   </div>
//
// Calling stopPropagation prevents xyflow's node-drag from also firing.

export function emitSubObjectDrag(
  e: DragEvent,
  subData: unknown,
  path: string,
  parentId: string,
): void {
  e.stopPropagation();
  e.dataTransfer.setData("application/json", JSON.stringify(subData));
  e.dataTransfer.setData(
    "application/x-ilinxa-subobject",
    JSON.stringify({ parentId, path }),
  );
  e.dataTransfer.effectAllowed = "copyMove";
}

import type { NodeData, NodeRenderer, Port } from "../types";

// Apply renderer.defaultPorts + renderer.defaultSubPorts to a NodeData ONLY
// where the corresponding `ports` field is absent. Presence of `ports` (even
// empty `[]`) is the deliberate-state signal — never re-inflate (Q23).
//
// Pure: returns a new NodeData; the input is untouched. Source-shape data is
// preserved this way.

export function inflateDefaultPorts(
  data: NodeData,
  renderer: NodeRenderer | undefined,
): NodeData {
  if (!renderer) return data;

  let out: NodeData = data;

  // Root-level ports inflation
  if (!Object.prototype.hasOwnProperty.call(data, "ports") && renderer.defaultPorts) {
    const ports: Port[] = renderer.defaultPorts(data);
    out = { ...out, ports };
  }

  // Sub-object port inflation, by JSON path. We support a small subset of
  // path syntax: dot-path and array-index (`media[0].thumb`). Plan §3.5
  // commits to this shape; richer JSONPath is a future extension.
  if (renderer.defaultSubPorts) {
    const subMap = renderer.defaultSubPorts(data);
    for (const [path, defaultPorts] of Object.entries(subMap)) {
      out = setPortsAtPath(out, path, defaultPorts);
    }
  }

  return out;
}

// Apply `ports` to the object at `path` inside `data`, ONLY if absent.
// Immutable — clones the affected branches.
function setPortsAtPath(
  data: NodeData,
  path: string,
  ports: Port[],
): NodeData {
  const segments = parsePath(path);
  if (segments.length === 0) return data;

  const cloned = JSON.parse(JSON.stringify(data)) as NodeData;
  let cursor: unknown = cloned;
  for (let i = 0; i < segments.length; i++) {
    const seg = segments[i];
    if (cursor === null || typeof cursor !== "object") return data;
    if (seg.kind === "key") {
      cursor = (cursor as Record<string, unknown>)[seg.value];
    } else {
      if (!Array.isArray(cursor)) return data;
      cursor = cursor[seg.value];
    }
  }
  if (!cursor || typeof cursor !== "object" || Array.isArray(cursor)) return data;
  const obj = cursor as Record<string, unknown>;
  if (Object.prototype.hasOwnProperty.call(obj, "ports")) return data; // respect existing
  obj.ports = ports;
  return cloned;
}

type PathSegment =
  | { kind: "key"; value: string }
  | { kind: "index"; value: number };

function parsePath(path: string): PathSegment[] {
  // Splits "media[0].thumb" → [{key,'media'},{index,0},{key,'thumb'}]
  const out: PathSegment[] = [];
  const re = /([^.[\]]+)|\[(\d+)\]/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(path)) !== null) {
    if (m[1] !== undefined) out.push({ kind: "key", value: m[1] });
    else if (m[2] !== undefined) out.push({ kind: "index", value: Number(m[2]) });
  }
  return out;
}

// Safe JSON parse — does NOT throw. Returns the parsed value on success or
// `undefined` on any error (with a dev-only `console.warn`). Used by the
// drop / paste pipelines so an invalid payload aborts cleanly.

export function parseJsonSafe(text: string): unknown {
  if (!text) return undefined;
  try {
    return JSON.parse(text);
  } catch (err) {
    if (process.env.NODE_ENV !== "production") {
      console.warn("[flow-canvas-01] could not parse JSON payload:", err);
    }
    return undefined;
  }
}

import type { NodeData, Port } from "../types";

// Pure tree-walker. Returns the first port matching `portId` at any depth,
// plus the JSON path to its containing object. Walker assumes port ids are
// unique within a node (locked decision Q9 / plan §3.4).

export type FoundPort = {
  port: Port;
  path: string; // JSONPath to the containing object — "" for root
};

export function findPortInTree(
  data: NodeData,
  portId: string,
): FoundPort | undefined {
  return walk(data, portId, "");
}

function walk(
  value: unknown,
  portId: string,
  path: string,
): FoundPort | undefined {
  if (!value || typeof value !== "object") return undefined;

  if (Array.isArray(value)) {
    for (let i = 0; i < value.length; i++) {
      const found = walk(value[i], portId, `${path}[${i}]`);
      if (found) return found;
    }
    return undefined;
  }

  const obj = value as Record<string, unknown>;

  // Direct port match — this object owns ports[]
  const ports = obj.ports;
  if (Array.isArray(ports)) {
    for (const p of ports) {
      if (p && typeof p === "object" && (p as Port).id === portId) {
        return { port: p as Port, path };
      }
    }
  }

  // Recurse into children
  for (const [key, child] of Object.entries(obj)) {
    if (key === "ports") continue;
    if (key === "__type") continue;
    const childPath = path ? `${path}.${key}` : key;
    const found = walk(child, portId, childPath);
    if (found) return found;
  }
  return undefined;
}

// Convenience: count edges whose `nodeId:portId` matches a side.
// Used by the connection validator for `multi: false` enforcement.
export function countEdgesAtPort(
  edges: ReadonlyArray<{
    source: string;
    target: string;
    sourceHandle?: string | null;
    targetHandle?: string | null;
  }>,
  nodeId: string,
  portId: string,
  side: "source" | "target",
): number {
  if (side === "source") {
    return edges.filter(
      (e) => e.source === nodeId && (e.sourceHandle ?? "") === portId,
    ).length;
  }
  return edges.filter(
    (e) => e.target === nodeId && (e.targetHandle ?? "") === portId,
  ).length;
}

/**
 * Inline shallow-equality helper. Matches zustand's `shallow` algorithm
 * (zustand v3/v4/v5 — algorithm unchanged) without taking on a transitive
 * dep on zustand itself. Used by xyflow's `useStore(selector, equality?)`
 * second arg where the default identity equality thrashes — e.g. a
 * selector that looks up an object in a Map and returns it: the lookup
 * resolves to the same underlying object, but xyflow's store updates the
 * Map reference on every change, so the selector returns a fresh reference
 * even when the meaningful contents are unchanged.
 *
 * Map / Set comparison is intentionally omitted — selectors in this
 * codebase never return those.
 *
 * Kept in the sealed folder (rather than importing from `zustand/shallow`)
 * for registry-portability: this avoids leaking a transitive zustand dep
 * to consumers of `@ilinxa/flow-canvas-01` who haven't otherwise installed
 * it. xyflow's own zustand peer is nested and doesn't surface to consumer
 * package.json. v0.2.0 Tier 2 plan F-01.
 */
export function shallow<T>(a: T, b: T): boolean {
  if (Object.is(a, b)) return true;
  if (typeof a !== "object" || a === null) return false;
  if (typeof b !== "object" || b === null) return false;
  const aKeys = Object.keys(a as object);
  const bKeys = Object.keys(b as object);
  if (aKeys.length !== bKeys.length) return false;
  for (const k of aKeys) {
    if (!Object.prototype.hasOwnProperty.call(b, k)) return false;
    if (
      !Object.is(
        (a as Record<string, unknown>)[k],
        (b as Record<string, unknown>)[k],
      )
    ) {
      return false;
    }
  }
  return true;
}

import type { NodeData } from "../types";

// Mutate `data` to remove the value at `path`. Pure: returns a new tree;
// the input is not modified. Supports dot-paths and array indices —
// `media[0]`, `slots[2].thumb`.
//
// Used by the sub-object extraction pipeline when the user holds Alt on
// drop (move semantics): the new node spawns AND the parent loses the
// sub-object via `onNodeUpdate`.

export function removeAtPath(data: NodeData, path: string): NodeData {
  const segments = parsePath(path);
  if (segments.length === 0) return data;
  const cloned = JSON.parse(JSON.stringify(data)) as NodeData;
  removeAtPathMut(cloned as unknown, segments);
  return cloned;
}

type Segment =
  | { kind: "key"; value: string }
  | { kind: "index"; value: number };

function parsePath(path: string): Segment[] {
  const out: Segment[] = [];
  const re = /([^.[\]]+)|\[(\d+)\]/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(path)) !== null) {
    if (m[1] !== undefined) out.push({ kind: "key", value: m[1] });
    else if (m[2] !== undefined) out.push({ kind: "index", value: Number(m[2]) });
  }
  return out;
}

function removeAtPathMut(cursor: unknown, segments: Segment[]): void {
  if (segments.length === 0) return;
  if (cursor === null || typeof cursor !== "object") return;
  const last = segments[segments.length - 1];
  const parents = segments.slice(0, -1);

  let parent: unknown = cursor;
  for (const seg of parents) {
    if (parent === null || typeof parent !== "object") return;
    if (seg.kind === "key") {
      parent = (parent as Record<string, unknown>)[seg.value];
    } else {
      if (!Array.isArray(parent)) return;
      parent = parent[seg.value];
    }
  }
  if (parent === null || typeof parent !== "object") return;

  if (last.kind === "index") {
    if (!Array.isArray(parent)) return;
    parent.splice(last.value, 1);
  } else {
    delete (parent as Record<string, unknown>)[last.value];
  }
}

import type { CanvasData, NodeData } from "../types";

/**
 * Walk-and-replace the `data` field of a single node by id. Returns a new
 * `CanvasData` reference (immutable update — does NOT mutate the input).
 * Returns the input unchanged if `nodeId` is not found.
 *
 * Shipped as a typed utility so consumers wiring `onEditRequest` + a dialog
 * don't reinvent it. See the `rich-card-in-flow` procomp guide for the
 * canonical popup-edit pattern. v0.2.1 addition.
 *
 * @example
 *   const next = updateNodeData(canvas, editingNodeId, newRichCardTree);
 *   setCanvas(next);
 */
export function updateNodeData(
  canvas: CanvasData,
  nodeId: string,
  nextData: NodeData,
): CanvasData {
  const idx = canvas.nodes.findIndex((n) => n.id === nodeId);
  if (idx < 0) return canvas;
  const nextNodes = canvas.nodes.slice();
  nextNodes[idx] = { ...nextNodes[idx], data: nextData };
  return { ...canvas, nodes: nextNodes };
}

"use client";

import { memo } from "react";
import { Background as XyBackground, BackgroundVariant } from "@xyflow/react";
import { cn } from "@/lib/utils";
import type { FlowCanvasBackgroundConfig } from "../types";

const DEFAULT_LIGHT = {
  from: "var(--background)",
  to: "var(--muted)",
  angle: 145,
};
const DEFAULT_DARK = {
  from: "var(--background)",
  to: "var(--card)",
  angle: 145,
};

const VARIANT_MAP = {
  dots: BackgroundVariant.Dots,
  grid: BackgroundVariant.Lines,
  cross: BackgroundVariant.Cross,
} as const;

function FlowCanvasBackgroundImpl({
  config,
}: {
  config?: FlowCanvasBackgroundConfig;
}) {
  const light = { ...DEFAULT_LIGHT, ...config?.light };
  const dark = { ...DEFAULT_DARK, ...config?.dark };
  const overlay = config?.overlay ?? "dots";
  const overlayOpacity = config?.overlayOpacity ?? 0.4;

  return (
    <>
      <div
        aria-hidden
        className={cn(
          "pointer-events-none absolute inset-0 transition-opacity",
          "[background:linear-gradient(var(--flow-canvas-light-angle),var(--flow-canvas-light-from),var(--flow-canvas-light-to))]",
          "dark:[background:linear-gradient(var(--flow-canvas-dark-angle),var(--flow-canvas-dark-from),var(--flow-canvas-dark-to))]",
        )}
        style={
          {
            "--flow-canvas-light-from": light.from,
            "--flow-canvas-light-to": light.to,
            "--flow-canvas-light-angle": `${light.angle}deg`,
            "--flow-canvas-dark-from": dark.from,
            "--flow-canvas-dark-to": dark.to,
            "--flow-canvas-dark-angle": `${dark.angle}deg`,
          } as React.CSSProperties
        }
      />
      {overlay !== "none" && (
        <XyBackground
          variant={VARIANT_MAP[overlay]}
          gap={20}
          size={1}
          color="var(--border)"
          style={{ opacity: overlayOpacity }}
        />
      )}
    </>
  );
}

export const FlowCanvasBackground = memo(FlowCanvasBackgroundImpl);

"use client";

import {
  Copy,
  CopyPlus,
  FileJson,
  Maximize2,
  RotateCcw,
  Scissors,
  Trash2,
} from "lucide-react";
import { useCallback, useState, type ReactNode } from "react";
import { useReactFlow } from "@xyflow/react";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuLabel,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { findRenderer } from "../registries/renderer-registry";
import { useFlowCanvasContext } from "../registries/canvas-context";
import type {
  EdgeRecord,
  FlowCanvasProps,
  MenuItem,
  NodeData,
  NodeRecord,
} from "../types";
import { PasteDialog } from "./paste-dialog";

type Target =
  | { kind: "canvas"; point: { x: number; y: number } }
  | { kind: "node"; node: NodeRecord }
  | { kind: "edge"; edge: EdgeRecord };

type Actions = {
  duplicateNode: (id: string) => void;
  deleteNode: (id: string) => void;
  deleteEdge: (id: string) => void;
  updateNodeData: (id: string, mutate: (d: NodeData) => NodeData) => void;
  extractSubObject: (input: {
    parentId: string;
    path: string;
    gesture: "copy" | "move";
    newNode: NodeRecord;
  }) => void;
  appendNode: (node: NodeRecord) => void;
};

export function CanvasContextMenu({
  children,
  readOnly,
  menuItems,
  getNodeById,
  getEdgeById,
  actions,
}: {
  children: ReactNode;
  readOnly: boolean;
  menuItems: FlowCanvasProps["menuItems"];
  // Resolver-based lookup — avoids re-rendering the menu on every drag tick.
  // Pre-v0.1.2 took `nodes: NodeRecord[]` + `edges: EdgeRecord[]` which
  // forced a full ~200-element re-map per state update.
  getNodeById: (id: string) => NodeRecord | undefined;
  getEdgeById: (id: string) => EdgeRecord | undefined;
  actions: Actions;
}) {
  const { renderers } = useFlowCanvasContext();
  const { fitView, zoomTo, screenToFlowPosition } = useReactFlow();
  const [target, setTarget] = useState<Target | null>(null);
  const [pasteOpen, setPasteOpen] = useState(false);
  const [pastePoint, setPastePoint] = useState<{ x: number; y: number } | null>(
    null,
  );

  // Resolve what was right-clicked. The xyflow DOM exposes data-id on
  // .react-flow__node and .react-flow__edge.
  const handleContextMenu = useCallback(
    (e: React.MouseEvent<HTMLElement>) => {
      const el = e.target as HTMLElement;
      const nodeEl = el.closest("[data-id]") as HTMLElement | null;
      const isNode = nodeEl?.classList.contains("react-flow__node") ?? false;
      const edgeEl = el.closest(".react-flow__edge") as HTMLElement | null;
      const isEdge = !!edgeEl;

      if (isNode && nodeEl) {
        const id = nodeEl.getAttribute("data-id");
        const node = id ? getNodeById(id) : undefined;
        if (node) {
          setTarget({ kind: "node", node });
          return;
        }
      }
      if (isEdge && edgeEl) {
        const id = edgeEl.getAttribute("data-id");
        const edge = id ? getEdgeById(id) : undefined;
        if (edge) {
          setTarget({ kind: "edge", edge });
          return;
        }
      }
      const point = screenToFlowPosition({ x: e.clientX, y: e.clientY });
      setTarget({ kind: "canvas", point });
    },
    [getNodeById, getEdgeById, screenToFlowPosition],
  );

  const copyAsJson = useCallback((node: NodeRecord) => {
    const text = JSON.stringify(node.data, null, 2);
    if (typeof navigator !== "undefined" && navigator.clipboard) {
      navigator.clipboard.writeText(text).catch(() => undefined);
    }
  }, []);

  const convertToCustomJson = useCallback(
    (node: NodeRecord) => {
      actions.updateNodeData(node.id, (d) => ({ ...d, __type: "custom-json" }));
    },
    [actions],
  );

  const addCustomNode = useCallback(
    (point: { x: number; y: number }) => {
      const node: NodeRecord = {
        id:
          typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
            ? crypto.randomUUID()
            : `n-${Math.random().toString(36).slice(2, 10)}`,
        position: point,
        data: { __type: "custom-json", _label: "Custom JSON" },
      };
      actions.appendNode(node);
    },
    [actions],
  );

  return (
    <>
      <ContextMenu>
        <ContextMenuTrigger asChild>
          <div onContextMenu={handleContextMenu} className="contents">
            {children}
          </div>
        </ContextMenuTrigger>
        <ContextMenuContent>
          {target?.kind === "node" && (
            <NodeMenu
              node={target.node}
              renderers={renderers}
              readOnly={readOnly}
              consumerItems={menuItems?.node}
              onCopyJson={copyAsJson}
              onConvert={convertToCustomJson}
              onDuplicate={actions.duplicateNode}
              onDelete={actions.deleteNode}
              onExtract={(path) =>
                extractFromNode(target.node, path, actions.extractSubObject)
              }
            />
          )}
          {target?.kind === "edge" && (
            <EdgeMenu
              edge={target.edge}
              readOnly={readOnly}
              consumerItems={menuItems?.edge}
              onDelete={actions.deleteEdge}
            />
          )}
          {target?.kind === "canvas" && (
            <PaneMenu
              readOnly={readOnly}
              consumerItems={menuItems?.canvas}
              onPaste={() => {
                setPastePoint(target.point);
                setPasteOpen(true);
              }}
              onAddCustom={() => addCustomNode(target.point)}
              onFitView={() => fitView({ duration: 200 })}
              onResetZoom={() => zoomTo(1, { duration: 150 })}
            />
          )}
        </ContextMenuContent>
      </ContextMenu>
      <PasteDialog
        open={pasteOpen}
        onOpenChange={setPasteOpen}
        onSubmit={(data) => {
          if (!pastePoint) return;
          const node: NodeRecord = {
            id:
              typeof crypto !== "undefined" &&
              typeof crypto.randomUUID === "function"
                ? crypto.randomUUID()
                : `n-${Math.random().toString(36).slice(2, 10)}`,
            position: pastePoint,
            data,
          };
          actions.appendNode(node);
          setPasteOpen(false);
        }}
      />
    </>
  );
}

// ─── Pane (canvas) menu ───────────────────────────────────────────────

function PaneMenu({
  readOnly,
  consumerItems,
  onPaste,
  onAddCustom,
  onFitView,
  onResetZoom,
}: {
  readOnly: boolean;
  consumerItems?: MenuItem[];
  onPaste: () => void;
  onAddCustom: () => void;
  onFitView: () => void;
  onResetZoom: () => void;
}) {
  return (
    <>
      <ContextMenuLabel>Canvas</ContextMenuLabel>
      {!readOnly && (
        <>
          <ContextMenuItem onSelect={onPaste}>
            <FileJson aria-hidden />
            Paste JSON…
          </ContextMenuItem>
          <ContextMenuItem onSelect={onAddCustom}>
            <CopyPlus aria-hidden />
            Add custom node
          </ContextMenuItem>
          <ContextMenuSeparator />
        </>
      )}
      <ContextMenuItem onSelect={onFitView}>
        <Maximize2 aria-hidden />
        Fit view
      </ContextMenuItem>
      <ContextMenuItem onSelect={onResetZoom}>
        <RotateCcw aria-hidden />
        Reset zoom
      </ContextMenuItem>
      {consumerItems && consumerItems.length > 0 && (
        <>
          <ContextMenuSeparator />
          <ConsumerItems items={consumerItems} />
        </>
      )}
    </>
  );
}

// ─── Node menu ────────────────────────────────────────────────────────

function NodeMenu({
  node,
  renderers,
  readOnly,
  consumerItems,
  onCopyJson,
  onConvert,
  onDuplicate,
  onDelete,
  onExtract,
}: {
  node: NodeRecord;
  renderers: ReturnType<typeof useFlowCanvasContext>["renderers"];
  readOnly: boolean;
  consumerItems?: (n: NodeRecord) => MenuItem[];
  onCopyJson: (n: NodeRecord) => void;
  onConvert: (n: NodeRecord) => void;
  onDuplicate: (id: string) => void;
  onDelete: (id: string) => void;
  onExtract: (path: string) => void;
}) {
  const renderer = findRenderer(renderers, node.data.__type);
  const extractablePaths = renderer?.extractablePaths?.(node.data) ?? [];
  const consumerExtras = consumerItems ? consumerItems(node) : [];

  return (
    <>
      <ContextMenuLabel className="truncate">
        {renderer?.label ?? node.data.__type}
      </ContextMenuLabel>
      <ContextMenuItem onSelect={() => onCopyJson(node)}>
        <Copy aria-hidden />
        Copy as JSON
      </ContextMenuItem>
      {!readOnly && (
        <>
          <ContextMenuItem onSelect={() => onDuplicate(node.id)}>
            <CopyPlus aria-hidden />
            Duplicate
          </ContextMenuItem>
          {node.data.__type !== "custom-json" && (
            <ContextMenuItem onSelect={() => onConvert(node)}>
              <FileJson aria-hidden />
              Convert to custom-JSON
            </ContextMenuItem>
          )}
          {extractablePaths.length > 0 && (
            <>
              <ContextMenuSeparator />
              <ContextMenuLabel className="text-[10px]">
                Extract sub-object
              </ContextMenuLabel>
              {extractablePaths.map((path) => (
                <ContextMenuItem key={path} onSelect={() => onExtract(path)}>
                  <Scissors aria-hidden />
                  {path}
                </ContextMenuItem>
              ))}
            </>
          )}
          <ContextMenuSeparator />
          <ContextMenuItem
            variant="destructive"
            onSelect={() => onDelete(node.id)}
          >
            <Trash2 aria-hidden />
            Delete
          </ContextMenuItem>
        </>
      )}
      {consumerExtras.length > 0 && (
        <>
          <ContextMenuSeparator />
          <ConsumerItems items={consumerExtras} />
        </>
      )}
    </>
  );
}

// ─── Edge menu ────────────────────────────────────────────────────────

function EdgeMenu({
  edge,
  readOnly,
  consumerItems,
  onDelete,
}: {
  edge: EdgeRecord;
  readOnly: boolean;
  consumerItems?: (e: EdgeRecord) => MenuItem[];
  onDelete: (id: string) => void;
}) {
  const consumerExtras = consumerItems ? consumerItems(edge) : [];
  return (
    <>
      <ContextMenuLabel className="truncate">Edge</ContextMenuLabel>
      {!readOnly && (
        <ContextMenuItem
          variant="destructive"
          onSelect={() => onDelete(edge.id)}
        >
          <Trash2 aria-hidden />
          Delete
        </ContextMenuItem>
      )}
      {consumerExtras.length > 0 && (
        <>
          <ContextMenuSeparator />
          <ConsumerItems items={consumerExtras} />
        </>
      )}
    </>
  );
}

// ─── Consumer-supplied items ──────────────────────────────────────────

function ConsumerItems({ items }: { items: MenuItem[] }) {
  return (
    <>
      {items.map((item) =>
        item.separatorBefore ? (
          <ContextMenuSeparator key={`sep-${item.id}`} />
        ) : (
          <ContextMenuItem
            key={item.id}
            disabled={item.disabled}
            onSelect={item.onSelect}
          >
            {item.icon}
            {item.label}
          </ContextMenuItem>
        ),
      )}
    </>
  );
}

// ─── Helpers ──────────────────────────────────────────────────────────

function extractFromNode(
  parent: NodeRecord,
  path: string,
  extractSubObject: Actions["extractSubObject"],
) {
  // Walk parent.data at `path` to grab the sub-data, then dispatch as a
  // copy-extract (no Alt-modifier through the menu — keyboard-first
  // accessibility per Q10 / plan §3.8).
  const sub = walkPathRead(parent.data, path);
  if (!sub) return;

  const subData =
    typeof (sub as Record<string, unknown>).__type === "string"
      ? (sub as NodeData)
      : { __type: "custom-json" as const, ...(sub as Record<string, unknown>) };

  const newNode: NodeRecord = {
    id:
      typeof crypto !== "undefined" && typeof crypto.randomUUID === "function"
        ? crypto.randomUUID()
        : `n-${Math.random().toString(36).slice(2, 10)}`,
    position: { x: parent.position.x + 320, y: parent.position.y + 40 },
    data: subData,
  };
  extractSubObject({
    parentId: parent.id,
    path,
    gesture: "copy",
    newNode,
  });
}

function walkPathRead(data: unknown, path: string): unknown {
  const re = /([^.[\]]+)|\[(\d+)\]/g;
  let cursor: unknown = data;
  let m: RegExpExecArray | null;
  while ((m = re.exec(path)) !== null) {
    if (cursor === null || typeof cursor !== "object") return undefined;
    if (m[1] !== undefined) {
      cursor = (cursor as Record<string, unknown>)[m[1]];
    } else if (m[2] !== undefined) {
      if (!Array.isArray(cursor)) return undefined;
      cursor = cursor[Number(m[2])];
    }
  }
  return cursor;
}

"use client";

// Side-effect import — selection-ring CSS keyed on xyflow's `.react-flow__node.selected`
// wrapper class. Sealed-folder file; auto-bundled by the host build (Turbopack /
// shadcn-registry). v0.2.0 Tier 2 plan §5.3.
import "../flow-canvas-01.css";

import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import {
  ConnectionMode,
  Controls,
  ReactFlow,
  type Connection,
  type Edge as XyEdge,
  type IsValidConnection,
  type Node as XyNode,
} from "@xyflow/react";
import { cn } from "@/lib/utils";
import { useCanvasData } from "../hooks/use-canvas-data";
import { useDropPipeline } from "../hooks/use-drop-pipeline";
import { useExportHandle } from "../hooks/use-export";
import { countEdgesAtPort, findPortInTree } from "../lib/port-walker";
import { useFlowCanvasContext } from "../registries/canvas-context";
import type {
  FlowCanvasBackgroundConfig,
  FlowCanvasProps,
  NodeData,
} from "../types";
import { FlowCanvasBackground } from "./background";
import { CanvasContextMenu } from "./canvas-context-menu";
import { DefaultEdge } from "./default-edge";
import { NodeAdapter } from "./node-adapter";

// Module-scope nodeTypes / edgeTypes — required (see xyflow-react-pro skill).
// Recreating these in render would tear down + remount every node.
const NODE_TYPES = { "ilinxa-node": NodeAdapter };
const EDGE_TYPES = { "ilinxa-edge": DefaultEdge };

type CanvasInnerProps = Pick<
  FlowCanvasProps,
  | "data"
  | "defaultData"
  | "onChange"
  | "onBeforeDrop"
  | "onBeforeConnect"
  | "onNodeCreate"
  | "onNodeUpdate"
  | "onNodeDelete"
  | "onEdgeCreate"
  | "onEdgeDelete"
  | "onSubObjectExtract"
  | "menuItems"
  | "panOnDrag"
  | "zoomOnScroll"
  | "selectionMode"
  | "readOnly"
  | "onlyRenderVisibleElements"
  | "exportRef"
  | "background"
  | "className"
> & {
  ariaLabel?: string;
  backgroundConfig: FlowCanvasBackgroundConfig | undefined;
};

export function Canvas({
  data,
  defaultData,
  onChange,
  onBeforeDrop,
  onBeforeConnect,
  onNodeCreate,
  onNodeUpdate,
  onNodeDelete,
  onEdgeCreate,
  onEdgeDelete,
  onSubObjectExtract,
  menuItems,
  panOnDrag = true,
  zoomOnScroll = true,
  selectionMode = "multi",
  readOnly = false,
  onlyRenderVisibleElements = true,
  exportRef,
  ariaLabel,
  backgroundConfig,
  className,
}: CanvasInnerProps) {
  const canvas = useCanvasData({
    data,
    defaultData,
    onChange,
    onBeforeConnect,
    onNodeCreate,
    onNodeUpdate,
    onNodeDelete,
    onEdgeCreate,
    onEdgeDelete,
    onSubObjectExtract,
  });
  const { renderers } = useFlowCanvasContext();
  const drop = useDropPipeline({
    renderers,
    appendNode: canvas.appendNode,
    extractSubObject: canvas.extractSubObject,
    onBeforeDrop,
    onNodeCreate,
  });

  useExportHandle(exportRef, canvas.snapshot);

  const interactive = !readOnly;
  const multiSelectionKeyCode = useMemo(
    () => (selectionMode === "multi" ? "Shift" : null),
    [selectionMode],
  );

  // Honor an explicit initial viewport from CanvasData. When the consumer
  // supplies one (e.g. the stress fixture starts at zoom 0.9), we hand it
  // to ReactFlow as `defaultViewport` and disable `fitView` — otherwise
  // fitView wins and every node ends up on-screen, defeating
  // `onlyRenderVisibleElements` culling. Snapshot at mount with
  // useState(initializer) so subsequent pans/zooms don't reset the viewport.
  const [initialViewport] = useState(
    () => data?.viewport ?? defaultData?.viewport,
  );

  // Refs mirror latest xyNodes/xyEdges so isValidConnection — a stable
  // <ReactFlow> prop — can read fresh state without rebuilding on every
  // drag tick. Without this, at 200+ nodes ReactFlow reconciles every
  // tick (see xyflow-react-pro skill "Performance" + the v0.1.2 perf patch).
  const nodesRef = useRef(canvas.xyNodes);
  const edgesRef = useRef(canvas.xyEdges);
  useEffect(() => {
    nodesRef.current = canvas.xyNodes;
  }, [canvas.xyNodes]);
  useEffect(() => {
    edgesRef.current = canvas.xyEdges;
  }, [canvas.xyEdges]);

  // M3 typed-connection validator. Same `type` on both ends + opposite dirs
  // (out → in). Enforces `multi: false` by counting existing edges at the
  // candidate port. Per-handle override hooks land in plan §3.4 layer 3.
  const isValidConnection = useCallback<IsValidConnection<XyEdge>>(
    (c: Connection | XyEdge) => {
      const source = c.source;
      const target = c.target;
      const sourceHandle = c.sourceHandle ?? "";
      const targetHandle = c.targetHandle ?? "";
      if (!source || !target || !sourceHandle || !targetHandle) return false;

      const nodes = nodesRef.current;
      const edges = edgesRef.current;
      const srcNode = nodes.find((n) => n.id === source);
      const tgtNode = nodes.find((n) => n.id === target);
      if (!srcNode || !tgtNode) return false;

      const srcFound = findPortInTree(srcNode.data as NodeData, sourceHandle);
      const tgtFound = findPortInTree(tgtNode.data as NodeData, targetHandle);
      if (!srcFound || !tgtFound) return false;

      // Direction: source handle must be `out`, target handle must be `in`.
      if (srcFound.port.dir !== "out" || tgtFound.port.dir !== "in") return false;

      // Type match.
      if (srcFound.port.type !== tgtFound.port.type) return false;

      // multi: false enforcement.
      if (
        !srcFound.port.multi &&
        countEdgesAtPort(edges, source, sourceHandle, "source") > 0
      ) {
        return false;
      }
      if (
        !tgtFound.port.multi &&
        countEdgesAtPort(edges, target, targetHandle, "target") > 0
      ) {
        return false;
      }
      return true;
    },
    [],
  );

  // Actions wrapper for the context menu. Stable object reference — its
  // members are already stable from useCanvasData's ref-based callbacks.
  const menuActions = useMemo(
    () => ({
      duplicateNode: canvas.duplicateNode,
      deleteNode: canvas.deleteNode,
      deleteEdge: canvas.deleteEdge,
      updateNodeData: canvas.updateNodeData,
      extractSubObject: canvas.extractSubObject,
      appendNode: canvas.appendNode,
    }),
    [
      canvas.duplicateNode,
      canvas.deleteNode,
      canvas.deleteEdge,
      canvas.updateNodeData,
      canvas.extractSubObject,
      canvas.appendNode,
    ],
  );

  return (
    <CanvasContextMenu
      readOnly={readOnly}
      menuItems={menuItems}
      getNodeById={canvas.getNodeById}
      getEdgeById={canvas.getEdgeById}
      actions={menuActions}
    >
      <div
        role="region"
        aria-label={ariaLabel ?? "Flow canvas"}
        data-flow-canvas-root=""
        tabIndex={0}
        className={cn(
          "relative h-full w-full overflow-hidden rounded-lg border border-border bg-background",
          "outline-none focus-visible:ring-2 focus-visible:ring-ring/50",
          className,
        )}
        onDragOver={interactive ? drop.onDragOver : undefined}
        onDrop={interactive ? drop.onDrop : undefined}
        onPaste={interactive ? drop.onPaste : undefined}
      >
        <FlowCanvasBackground config={backgroundConfig} />
        <ReactFlow<XyNode<NodeData>, XyEdge>
          nodes={canvas.xyNodes}
          edges={canvas.xyEdges}
          onNodesChange={canvas.onNodesChange}
          onEdgesChange={canvas.onEdgesChange}
          onConnect={canvas.onConnect}
          onNodeDragStart={canvas.onNodeDragStart}
          onNodeDragStop={canvas.onNodeDragStop}
          isValidConnection={isValidConnection}
          connectionMode={ConnectionMode.Strict}
          nodeTypes={NODE_TYPES}
          edgeTypes={EDGE_TYPES}
          panOnDrag={panOnDrag}
          zoomOnScroll={zoomOnScroll}
          nodesDraggable={interactive}
          nodesConnectable={interactive}
          elementsSelectable={interactive}
          deleteKeyCode={interactive ? ["Backspace", "Delete"] : null}
          multiSelectionKeyCode={multiSelectionKeyCode}
          onlyRenderVisibleElements={onlyRenderVisibleElements}
          proOptions={{ hideAttribution: true }}
          defaultViewport={initialViewport}
          fitView={!initialViewport}
        >
          <Controls position="bottom-left" />
        </ReactFlow>
      </div>
    </CanvasContextMenu>
  );
}

