import { memo, useState } from "react";
import { cn } from "@/lib/utils";
import type { NodeData, NodeRenderer } from "../types";
import { PortsAt } from "./ports-at";

type CustomJsonData = NodeData & { _label?: string };

function deriveLabel(data: CustomJsonData): string {
  if (typeof data._label === "string" && data._label.length > 0) {
    return data._label;
  }
  if (data.__type === "custom-json") return "Custom JSON";
  return data.__type;
}

function CustomJsonNodeImpl({ data }: { data: CustomJsonData }) {
  const [expanded, setExpanded] = useState(false);
  const label = deriveLabel(data);

  // Collapsed mode is the hot path — at 200 nodes, the prior implementation
  // ran JSON.stringify on every node + rendered a CSS-truncated <pre> + the
  // whole card carried a box-shadow. Skip all three when collapsed: render
  // the label only, no <pre>, no shadow. Expanded mode keeps the full
  // stringified payload (only one node is expanded at a time in practice).
  return (
    <div
      className={cn(
        "relative min-w-45 max-w-90 rounded-md border border-border bg-card text-card-foreground",
        expanded && "shadow-sm",
      )}
    >
      <button
        type="button"
        onClick={() => setExpanded((v) => !v)}
        className={cn(
          "flex w-full items-center justify-between gap-2 px-3 py-2",
          "text-left text-xs font-medium",
          expanded && "border-b border-border",
        )}
      >
        <span className="truncate font-mono text-muted-foreground">
          {label}
        </span>
        <span aria-hidden className="text-muted-foreground">
          {expanded ? "−" : "+"}
        </span>
      </button>
      {expanded && (
        <pre className="max-h-80 overflow-auto whitespace-pre p-3 font-mono text-[11px] leading-snug text-muted-foreground">
          <code>{JSON.stringify(data, null, 2)}</code>
        </pre>
      )}
      {/* Render port handles for any ports declared in data.ports. Without
       * these, xyflow's edge layer fails getEdgePosition() for every edge
       * referencing this node and logs hundreds of warnings per frame.
       * Discovered via 2026-05-14 baseline measurement — the cliff at
       * N≥100 in vis-off was warning-spam CPU cost, not React reconciliation
       * cost. v0.1.4 patch. */}
      <PortsAt ports={data.ports} position="left" />
      <PortsAt ports={data.ports} position="right" />
      <PortsAt ports={data.ports} position="top" />
      <PortsAt ports={data.ports} position="bottom" />
    </div>
  );
}

export const CustomJsonNode = memo(CustomJsonNodeImpl);

export const customJsonRenderer: NodeRenderer<CustomJsonData> = {
  type: "custom-json",
  label: "Custom JSON",
  render: (data) => <CustomJsonNode data={data} />,
};

"use client";

import { memo } from "react";
import {
  BaseEdge,
  getSmoothStepPath,
  useStore,
  type EdgeProps,
} from "@xyflow/react";
import { findPortInTree } from "../lib/port-walker";
import { usePortType } from "../registries/port-type-registry";
import type { EdgeRenderer, NodeData, Port } from "../types";

// M3 polish: pull the source port's type color and use it as the edge
// stroke. Each connection gets the visual identity of its data type — text
// edges = blue, image = emerald, card = lime — making the graph readable at
// a glance without requiring a legend.

// Narrow comparator for the source-port useStore selector. The returned
// shape is `Port | undefined`; only three fields (`id`, `type`, `multi`)
// affect this renderer — `type` drives the stroke color via portType
// lookup; `id` and `multi` are kept stable for identity guards. Without
// this, xyflow's store updates the nodeLookup Map reference per change
// and the default identity equality re-runs the selector + re-renders the
// edge for every node change anywhere in the canvas. v0.2.0 Tier 2 plan F-01.
const portEqual = (a?: Port, b?: Port) =>
  a === b || (a?.id === b?.id && a?.type === b?.type && a?.multi === b?.multi);

function DefaultEdgeImpl(props: EdgeProps) {
  const {
    id,
    source,
    sourceHandleId,
    sourceX,
    sourceY,
    targetX,
    targetY,
    sourcePosition,
    targetPosition,
    markerStart,
    markerEnd,
    style,
    selected,
  } = props;

  // Reactive lookup of the source port via xyflow's store. Recomputes if the
  // source node's data tree changes. `portEqual` narrows re-render triggers
  // to the three fields this renderer actually reads (see comparator above).
  const sourcePort: Port | undefined = useStore(
    (s) => {
      if (!source || !sourceHandleId) return undefined;
      const node = s.nodeLookup.get(source);
      if (!node) return undefined;
      return findPortInTree(node.data as NodeData, sourceHandleId)?.port;
    },
    portEqual,
  );

  const portType = usePortType(sourcePort?.type ?? "");
  const color = portType?.color;

  const [path] = getSmoothStepPath({
    sourceX,
    sourceY,
    targetX,
    targetY,
    sourcePosition,
    targetPosition,
    borderRadius: 8,
  });

  return (
    <BaseEdge
      id={id}
      path={path}
      markerStart={markerStart}
      markerEnd={markerEnd}
      style={{
        stroke: selected ? "var(--ring)" : (color ?? "var(--xy-edge-stroke)"),
        strokeWidth: selected ? 2.5 : 1.5,
        ...style,
      }}
    />
  );
}

export const DefaultEdge = memo(DefaultEdgeImpl);

export const defaultEdgeRenderer: EdgeRenderer = {
  type: "smoothstep",
  label: "Smooth step",
  // For consumer-facing dispatch (M3 polish has wired this internally — the
  // single 'ilinxa-edge' xyflow type calls DefaultEdge directly). Custom
  // edge renderers via the edge-type registry are exposed in v0.2.
  render: () => null,
};

"use client";

import { memo, useCallback, useMemo } from "react";
import type { NodeProps } from "@xyflow/react";
import { useFlowCanvasContext } from "../registries/canvas-context";
import { findRenderer } from "../registries/renderer-registry";
import type { NodeData, NodeRenderer, RenderContext } from "../types";
import { customJsonRenderer } from "./custom-json-node";
import { NodeShell } from "./node-shell";

// Build a self-referential renderChild via function declaration. Function
// declarations are hoisted within their own body so `rc` can reference itself
// without React Compiler's temporal-dead-zone warning.
function makeRenderChild(
  renderers: NodeRenderer[],
  nodeId: string,
  readOnly: boolean,
): RenderContext["renderChild"] {
  function rc(childData: NodeData) {
    const childRenderer =
      findRenderer(renderers, childData.__type) ?? customJsonRenderer;
    const childCtx: RenderContext = {
      nodeId,
      isSelected: false,
      isDragging: false,
      isReadOnly: readOnly,
      renderChild: rc,
    };
    return childRenderer.render(childData, childCtx);
  }
  return rc;
}

function NodeAdapterImpl(props: NodeProps) {
  const { id, data, selected, dragging, draggable } = props;
  const { renderers, readOnly, onEditRequest } = useFlowCanvasContext();

  const nodeData = data as NodeData;
  const renderer =
    findRenderer(renderers, nodeData.__type) ?? customJsonRenderer;

  const renderChild = useMemo(
    () => makeRenderChild(renderers, id, readOnly),
    [renderers, id, readOnly],
  );

  // v0.2.1 — bind canvas-level onEditRequest to this node's id so renderers
  // fire `ctx.onEditRequest(subPath?)` without knowing their own nodeId.
  // `onEditRequest` from context is itself stable (ref-mirrored in
  // flow-canvas-01.tsx, F-V5 lock); identity flips only on wired/unwired.
  const handleEditRequest = useCallback(
    (subPath?: string) => onEditRequest?.(id, subPath),
    [onEditRequest, id],
  );

  const ctx: RenderContext = {
    nodeId: id,
    isSelected: !!selected,
    isDragging: !!dragging,
    isReadOnly: readOnly,
    renderChild,
    // Leave undefined when consumer hasn't wired onEditRequest so renderers
    // can gate their click affordances via `if (ctx.onEditRequest)`.
    onEditRequest: onEditRequest ? handleEditRequest : undefined,
  };

  return (
    <NodeShell isLocked={draggable === false}>
      {renderer.render(nodeData, ctx)}
    </NodeShell>
  );
}

export const NodeAdapter = memo(NodeAdapterImpl);

