import { useState } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { coerceToNodeData } from "../lib/coerce-to-node-data";
import { parseJsonSafe } from "../lib/parse-json";
import type { NodeData } from "../types";

export function PasteDialog({
  open,
  onOpenChange,
  onSubmit,
}: {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSubmit: (data: NodeData) => void;
}) {
  const [text, setText] = useState("");
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = () => {
    setError(null);
    const parsed = parseJsonSafe(text);
    if (parsed === undefined) {
      setError("Could not parse — make sure the input is valid JSON.");
      return;
    }
    const data = coerceToNodeData(parsed);
    if (!data) {
      setError("JSON must be an object (arrays and primitives aren't nodes).");
      return;
    }
    onSubmit(data);
    setText("");
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Paste JSON</DialogTitle>
          <DialogDescription>
            Paste a JSON object to spawn it as a node. Unknown shapes render as
            a custom-JSON node automatically.
          </DialogDescription>
        </DialogHeader>
        <Textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder={`{"__type":"prompt","template":"Translate to French"}`}
          className="h-40 font-mono text-xs"
          autoFocus
        />
        {error && (
          <p className="text-xs text-destructive" role="alert">
            {error}
          </p>
        )}
        <DialogFooter>
          <Button variant="ghost" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button onClick={handleSubmit} disabled={!text.trim()}>
            Add node
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { Handle, Position, type IsValidConnection } from "@xyflow/react";
import { memo, type CSSProperties } from "react";
import { cn } from "@/lib/utils";
import { usePortType } from "../registries/port-type-registry";
import type { Port } from "../types";

const POSITION_MAP = {
  left: Position.Left,
  right: Position.Right,
  top: Position.Top,
  bottom: Position.Bottom,
} as const;

// Wraps xyflow's <Handle /> with our typed-port semantics:
// - Color comes from the port-type registry (via usePortType).
// - id is forced (xyflow needs unique handle ids per node when same type).
// - type is derived from port.dir ('out' → 'source', 'in' → 'target').
// - position from port.side via POSITION_MAP.
//
// In M2 the handle renders correctly. M3 wires `isValidConnection` on the
// handle to the global typed-connection validator + multi-edge enforcement.
function PortHandleImpl({
  port,
  isValidConnection,
  className,
  style,
}: {
  port: Port;
  isValidConnection?: IsValidConnection;
  className?: string;
  style?: CSSProperties;
}) {
  const portType = usePortType(port.type);
  const color = portType?.color ?? "var(--muted-foreground)";

  return (
    <Handle
      id={port.id}
      type={port.dir === "out" ? "source" : "target"}
      position={POSITION_MAP[port.side]}
      isValidConnection={isValidConnection}
      aria-label={`${port.label ?? port.id} (${port.dir} ${port.type})`}
      className={cn("h-2.5! w-2.5! border-2!", className)}
      style={{
        background: color,
        borderColor: "var(--background)",
        ...style,
      }}
    />
  );
}

export const PortHandle = memo(PortHandleImpl);

"use client";

import { memo, type CSSProperties } from "react";
import type { Port, PortSide, PortsAtProps } from "../types";
import { PortHandle } from "./port-handle";

// Layout helper: stacks handles along an edge of the renderer's bounding
// box. Handles are direct DOM children of the node (xyflow's <Handle> is
// `position: absolute` and uses its own `position` prop to anchor; wrapping
// it in another absolute div would break that). We stack by computing
// `top` (for left/right edges) or `left` (for top/bottom edges) inline.
//
// For the easy case — a node has 1–N ports on each edge, evenly stacked.
// For complex layouts (per-sub-object positioning), emit <PortHandle /> in
// the renderer directly with your own style overrides.

function isVertical(side: PortSide): boolean {
  return side === "left" || side === "right";
}

function offsetFor(
  position: PortSide,
  index: number,
  count: number,
  spacing: number,
): CSSProperties {
  // Centered stack: middle item at 50%, others spaced by `spacing` px.
  const centered = (index - (count - 1) / 2) * spacing;
  if (isVertical(position)) {
    return { top: `calc(50% + ${centered}px)` };
  }
  return { left: `calc(50% + ${centered}px)` };
}

function PortsAtImpl({ ports, position, spacing = 24 }: PortsAtProps) {
  if (!ports || ports.length === 0) return null;
  const filtered = ports.filter((p: Port) => p.side === position);
  if (filtered.length === 0) return null;

  return (
    <>
      {filtered.map((p, i) => (
        <PortHandle
          key={p.id}
          port={p}
          style={offsetFor(position, i, filtered.length, spacing)}
        />
      ))}
    </>
  );
}

export const PortsAt = memo(PortsAtImpl);

