import { createContext, useContext, type ReactNode } from "react";
import type {
  EdgeRenderer,
  NodeRecord,
  NodeRenderer,
  PortType,
} from "../types";

export type FlowCanvasContextValue = {
  renderers: NodeRenderer[];
  portTypes: PortType[];
  edgeTypes: EdgeRenderer[];
  readOnly: boolean;
  selectionMode: "single" | "multi";
  onNodeUpdate?: (node: NodeRecord) => void;
  // v0.2.1 — bubbled up from a renderer's ctx.onEditRequest call.
  // Identity is stabilized inside flow-canvas-01.tsx via ref-mirror so consumers
  // passing inline `onEditRequest={...}` don't cascade re-renders across every
  // NodeAdapter. Identity only flips on the wired/unwired transition.
  onEditRequest?: (nodeId: string, subPath?: string) => void;
};

export const FlowCanvasContext = createContext<FlowCanvasContextValue | null>(
  null,
);

export function useFlowCanvasContext(): FlowCanvasContextValue {
  const ctx = useContext(FlowCanvasContext);
  if (!ctx) {
    throw new Error(
      "useFlowCanvasContext must be used inside <FlowCanvas /> — wrap your tree in the FlowCanvas component before calling registry hooks.",
    );
  }
  return ctx;
}

export function FlowCanvasContextProvider({
  value,
  children,
}: {
  value: FlowCanvasContextValue;
  children: ReactNode;
}) {
  return (
    <FlowCanvasContext.Provider value={value}>
      {children}
    </FlowCanvasContext.Provider>
  );
}

"use client";

import type { EdgeRenderer } from "../types";
import { defaultEdgeRenderer } from "../parts/default-edge";
import { useFlowCanvasContext } from "./canvas-context";

export { defaultEdgeRenderer };

export function findEdgeType(
  edgeTypes: EdgeRenderer[],
  type: string,
): EdgeRenderer | undefined {
  return edgeTypes.find((t) => t.type === type);
}

export function useEdgeType(type: string): EdgeRenderer | undefined {
  const { edgeTypes } = useFlowCanvasContext();
  return findEdgeType(edgeTypes, type);
}

export function mergeEdgeTypes(
  consumer: EdgeRenderer[] | undefined,
): EdgeRenderer[] {
  const merged: EdgeRenderer[] = [defaultEdgeRenderer];
  const seen = new Set<string>([defaultEdgeRenderer.type]);
  for (const t of consumer ?? []) {
    if (seen.has(t.type) && process.env.NODE_ENV !== "production") {
      console.warn(
        `[flow-canvas-01] edge type collision for "${t.type}" — last-wins`,
      );
    }
    const idx = merged.findIndex((m) => m.type === t.type);
    if (idx >= 0) merged[idx] = t;
    else merged.push(t);
    seen.add(t.type);
  }
  return merged;
}

"use client";

import type { PortType } from "../types";
import { useFlowCanvasContext } from "./canvas-context";

// Built-in port-type palette. Maps to design tokens, not raw colors.
// — data:  neutral grey (untyped / generic)
// — text:  blue   (--chart-5)
// — image: emerald (--chart-2)
// — card:  signal-lime (--primary, the accent)
// — event: cyan  (--chart-4)
//
// Color descriptions in the description doc said "blue / orange / lime / rose" —
// the actual chart palette is lime → emerald → teal → cyan → blue, so we map to
// the closest semantic neighbor. Consumers override via the `portTypes` prop.
export const defaultPortTypes: PortType[] = [
  { id: "data", color: "var(--muted-foreground)", label: "Data" },
  { id: "text", color: "var(--chart-5)", label: "Text" },
  { id: "image", color: "var(--chart-2)", label: "Image" },
  { id: "card", color: "var(--primary)", label: "Card" },
  { id: "event", color: "var(--chart-4)", label: "Event" },
];

export function findPortType(
  portTypes: PortType[],
  id: string,
): PortType | undefined {
  return portTypes.find((t) => t.id === id);
}

export function usePortType(id: string): PortType | undefined {
  const { portTypes } = useFlowCanvasContext();
  return findPortType(portTypes, id);
}

"use client";

import type { NodeRenderer } from "../types";
import { customJsonRenderer } from "../parts/custom-json-node";
import { useFlowCanvasContext } from "./canvas-context";

export { customJsonRenderer };

export function findRenderer(
  renderers: NodeRenderer[],
  type: string,
): NodeRenderer | undefined {
  return renderers.find((r) => r.type === type);
}

export function useRenderer(type: string): NodeRenderer | undefined {
  const { renderers } = useFlowCanvasContext();
  return findRenderer(renderers, type);
}

// Merges built-in 'custom-json' renderer with consumer-supplied renderers.
// Last-wins on collision (consumer can deliberately override). Dev-mode warns.
export function mergeRenderers(
  consumer: NodeRenderer[] | undefined,
): NodeRenderer[] {
  const merged: NodeRenderer[] = [customJsonRenderer];
  const seen = new Set<string>([customJsonRenderer.type]);
  for (const r of consumer ?? []) {
    if (seen.has(r.type) && process.env.NODE_ENV !== "production") {
      console.warn(
        `[flow-canvas-01] renderer collision for "${r.type}" — last-wins`,
      );
    }
    const idx = merged.findIndex((m) => m.type === r.type);
    if (idx >= 0) merged[idx] = r;
    else merged.push(r);
    seen.add(r.type);
  }
  return merged;
}
